import axios from 'axios';

const API_URL = 'http://localhost:8080/HouseHub'; // Replace with your actual API URL

// Create a reusable Axios instance
const apiClient = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

export default {
  loginAdmin(data) {
    return apiClient.post("/loginuser", data);
  },
  loginUser(data) {
    return apiClient.post("/logincontact", data);
  },

  //----------- Lotes
  getLotes() {
    return apiClient.get("/lotes");
  },
  getLote(id) {
    return apiClient.get("/lotes/" + id);
  },
  createLote(item) {

    console.log('######################################');
    var regreso = apiClient.post("/lotes", item)
      .then(response => {
        // 🟢 La solicitud fue exitosa (código 2xx)
        console.log("Lote creado con éxito:", response.data);
        return response.data;
      })
      .catch(error => {
        // 🔴 La solicitud falló (códigos 4xx, 5xx)
        // Aquí manejas el error 415 (Unsupported Media Type)
        if (error.response) {
          // La solicitud se hizo y el servidor respondió con un código de estado
          // que está fuera del rango de 2xx
          console.error("Error al crear el lote:", error.response.status);
          console.error("Mensaje de error del servidor:", error.response.data);

          if (error.response.status === 415) {
            // Manejo específico del error 415
            alert("Error 415: El formato de los datos es incorrecto. Verifica el Content-Type.");
          }

        } else if (error.request) {
          // La solicitud se hizo, pero no se recibió respuesta
          console.error("No se recibió respuesta del servidor:", error.request);
        } else {
          // Algo más causó el error
          console.error("Error en la configuración de la solicitud:", error.message);
        }

        // Puedes lanzar una nueva excepción o retornar un valor para
        // que el componente que llama a este método también sepa que hubo un error.
        throw error;
      });
    console.log('######################################3');
    // Retorna el resultado de la promesa para que pueda ser manejado por el componente que llama a este método
    console.log('Regreso de createLote:', regreso);
    return regreso;
  },
  deleteLote(id) {
    return apiClient.delete("/lotes/" + id);
  },
  updateLote(item) {
    return apiClient.put("/lotes", item);
  },
  createLote(item) {
    return apiClient.post("/lotes", item);
  },


  //----------- Lote Types
  getTiposLote() {
    return apiClient.get("/lotetypes");
  },
  getTipoLote(id) {
    return apiClient.get("/lotetypes/" + id);
  },
  createTipoLote(data) {
    return apiClient.post("/lotetypes", data);
  },
  deleteTipoLote(id) {
    return apiClient.delete("/lotetypes/" + id);
  },
  updateTipoLote(data) {
    return apiClient.put("/lotetypes", data);
  },
  createTipoLote(data) {
    return apiClient.post("/lotetypes", data);
  },


  //----------- Cuota Types
  getTiposCuota() {
    return apiClient.get("/cuotatypes");
  },
  getTipoCuota(id) {
    return apiClient.get("/cuotatypes/" + id);
  },
  createTipoCuota(data) {
    return apiClient.post("/cuotatypes", data);
  },
  deleteTipoCuota(id) {
    return apiClient.delete("/cuotatypes/" + id);
  },
  updateTipoCuota(data) {
    return apiClient.put("/cuotatypes", data);
  },
  createTipoCuota(data) {
    return apiClient.post("/cuotatypes", data);
  },


  //----------- Contactos
  getContactos() {
    return apiClient.get("/contactos");
  },
  getContacto(id) {
    return apiClient.get("/contactos/" + id);
  },
  createContacto(item) {
    return apiClient.post("/contactos", item);
  },
  deleteContacto(id) {
    return apiClient.delete("/contactos/" + id);
  },
  updateContacto(item) {
    return apiClient.put("/contactos", item);
  },
  createContacto(item) {
    return apiClient.post("/contactos", item);
  },
  getContactosShort() {
    return apiClient.get("/contactosshort");
  },

  //----------- Condominios
  getCondominios() {
    return apiClient.get("/condominios");
  },
  getCondominio(id) {
    return apiClient.get("/condominios/" + id);
  },
  createCondominio(item) {
    return apiClient.post("/condominios", item);
  },
  deleteCondominio(id) {
    return apiClient.delete("/condominios/" + id);
  },
  updateCondominio(item) {
    return apiClient.put("/condominios", item);
  },
  createCondominio(item) {
    return apiClient.post("/condominios", item);
  },


};
